patch:
diff --git a/llvm/lib/Transforms/Utils/SCCPSolver.cpp b/llvm/lib/Transforms/Utils/SCCPSolver.cpp
index acb9911e8a52..fde72c0721e7 100644
--- a/llvm/lib/Transforms/Utils/SCCPSolver.cpp
+++ b/llvm/lib/Transforms/Utils/SCCPSolver.cpp
@@ -82,6 +82,36 @@ bool SCCPSolver::tryToReplaceWithConstant(Value *V) {

   LLVM_DEBUG(dbgs() << "  Constant: " << *Const << " = " << *V << '\n');

+  // Avoid replacing an alloca with a non-poison constant. Some intrinsics
+  // like llvm.lifetime.start/end require that their pointer operand be an
+  // alloca or poison. Propagating a path-local equality (e.g. from a branch
+  // comparing the alloca against a constant pointer) to a global replacement
+  // can produce invalid IR rejected by the verifier. Conservatively skip
+  // transforming allocas in this case.
+  if (!isa<PoisonValue>(Const)) {
+    // Avoid replacing an alloca with a non-poison constant. Some intrinsics
+    // like llvm.lifetime.start/end require that their pointer operand be an
+    // alloca or poison. Propagating a path-local equality (e.g. from a branch
+    // comparing the alloca against a constant pointer) to a global replacement
+    // can produce invalid IR rejected by the verifier. Conservatively skip
+    // transforming allocas in this case.
+    if (isa<AllocaInst>(V)) {
+      LLVM_DEBUG(dbgs() << "    Skipping replacement of alloca with constant: "
+                        << *V << " -> " << *Const << '\n');
+      return false;
+    }
+    // PredicateInfo may introduce SSA copies (e.g. bitcasts) of allocas to
+    // model branch-local predicates. Replacing such copies with a constant
+    // would also break lifetime intrinsics that still reference the copy.
+    if (auto *BC = dyn_cast<BitCastInst>(V)) {
+      if (isa<AllocaInst>(BC->getOperand(0)) && BC->getType() == BC->getOperand(0)->getType()) {
+        LLVM_DEBUG(dbgs() << "    Skipping replacement of alloca SSA copy with constant: "
+                          << *V << " -> " << *Const << '\n');
+        return false;
+      }
+    }
+  }
+
   // Replaces all of the uses of a variable with uses of the constant.
   V->replaceAllUsesWith(Const);
   return true;

